import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"金牌猎头","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/金牌猎头.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/金牌猎头.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/金牌猎头.md"};function p(l,a,_,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"金牌猎头",tabindex:"-1"},[s("金牌猎头 "),e("a",{class:"header-anchor",href:"#金牌猎头","aria-label":'Permalink to "金牌猎头"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风021")])])],-1),o('<h1 id="金牌猎头-1" tabindex="-1">金牌猎头 <a class="header-anchor" href="#金牌猎头-1" aria-label="Permalink to &quot;金牌猎头&quot;">​</a></h1><p>金牌猎头<br> D+500</p><p>这是一把金色枪身，白色手柄的单发重型手枪，配有瞄准镜。金牌猎头的子弹容量为8发，具有7L武器伤害，高速5，不具有速射等级。</p><p>金牌猎头初始不具有任何子弹，必须在影片开始前以250/发子弹的价格为金牌猎头购买子弹，上限为8发，金牌猎头无法获得无限子弹，也无法换弹，无法以4倍价格购买无限特殊子弹，无法使用其他特殊子弹。</p><p>猎头者：<br> 当使用金牌猎头对某一目标的头部进行射击时，猎头者将开始正常生效，这次射击将忽略对方头部的部位减值，且造成的部位攻击效果从【每2点伤害造成1点晕眩，以耐力-求生-强韧对抗】变为【如果伤害超过了对方的体积，则额外附带本次攻击的伤害出目扣除对方体积点晕眩，以标准豁免进行对抗】。猎头者触发时，金牌猎头额外获得2L武器伤害和1高速。</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
